const WeatherCard = ({ city, temperature, wind, humidity }) => {
  return (
    <div>
      <h2>{city}</h2>
      <h3>{temperature}</h3>
      <h4>{wind}</h4>
      <h4>{humidity}</h4>
    </div>
  );
};

export default WeatherCard;
